"use strict";parserFactory.register("chaleuria.com",()=>new ChaleuriaParser);class ChaleuriaParser extends WordpressBaseParser{constructor(){super()}async getChapterUrls(e){let t=e.querySelectorAll("table.toctable tr.tocrow");if(t.length>0)return[...t].map(e=>this.rowToChapter(e));{let t=e.querySelector(".entry-content");return util.hyperlinksToChapterList(t)}}rowToChapter(e){let t=e.querySelector("td.toctitle").textContent;return{sourceUrl:e.querySelector("button").getAttribute("formaction"),title:t}}findContent(e){return e.querySelector(".entry-content, div.elementor-widget-theme-post-content div.elementor-widget-container")}extractTitleImpl(e){return e.querySelector("h1.entry-title, h1.elementor-heading-title")}findChapterTitle(e){return e.querySelector("h1.entry-title, h1.elementor-heading-title")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".entry-content p, div.elementor-widget-theme-post-content div.elementor-widget-container p")]}cleanInformationNode(e){util.removeChildElementsMatchingSelector(e,"img")}}